const p = items[0].json.properties;
const get = (key) => p[key]?.value || 'N/A';

const name = `${get('firstname').trim()} ${get('lastname').trim()}`.trim();
const company = get('company') === 'UNKNOWN' ? 'N/A' : get('company');
const slug = company.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '') || 
  name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
const dateStr = get('createdate') !== 'N/A' ? new Date(get('createdate')).toLocaleDateString('en-US') : 'N/A';

const goals = get('website_intake_goals');
const industry = get('website_intake_industry');
const timeline = get('website_intake_timeline');
const pages = get('website_intake_pages');
const competitors = get('website_intake_competitors');
const designNotes = get('website_intake_design_notes');

const pageCount = pages !== 'N/A' ? pages.split(',').length : 0;
const goalLower = goals.toLowerCase();
let tier = 'Growth';
let tierReason = 'Mid-range page count and goals suggest Growth tier.';
if (pageCount <= 4 || goalLower.includes('simple')) {
  tier = 'Starter';
  tierReason = 'Limited pages and straightforward goals fit the Starter tier.';
} else if (pageCount > 8 || goalLower.includes('automat') || goalLower.includes('integrat')) {
  tier = 'Growth';
  tierReason = 'Multiple pages with automation or integration goals align with Growth tier.';
}

const gaps = [];
if (get('phone') === 'N/A') gaps.push('No phone number on file');
if (get('website') === 'N/A') gaps.push('No existing website URL provided');
if (competitors === 'N/A') gaps.push('No competitor or inspiration sites listed');
if (designNotes === 'N/A') gaps.push('No design direction notes');
if (timeline.toLowerCase().includes('flexible')) gaps.push('Timeline is flexible — confirm hard deadlines on discovery call');
if (company === 'N/A') gaps.push('Company name unknown — confirm on call');

const gapBlock = gaps.length > 0 ? gaps.map(g => `- ${g}`).join('\n') : '- No critical gaps identified';

const brief = `# Client Intake Brief
**Name:** ${name}
**Company:** ${company}
**Email:** ${get('email')}
**Phone:** ${get('phone')}
**Lead Status:** ${get('hs_lead_status')}
**Submitted:** ${dateStr}

---

## What They're Building
${name} is looking to build a website for ${company} in the ${industry} space. Their primary goals include ${goals.toLowerCase()}. Timeline is ${timeline.toLowerCase()}.

---

## Intake Details
- **Industry:** ${industry}
- **Goals:** ${goals}
- **Timeline:** ${timeline}
- **Pages Requested:** ${pages}
- **Competitors / Inspiration:** ${competitors}
- **Design Notes:** ${designNotes}

---

## Red Flags / Gaps
${gapBlock}

---

## Recommended IW Tier
**${tier}** — ${tierReason}
`;

return [{ json: { brief, slug, name } }];
